#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 5e5+5;
struct node{int x,y,tim,val;}d[N],tmp[N];
int n,Q,a[N],cnt,Tw,Mxu,c[N],Ans[N];
int Ls[N],cL;vector<int> ot;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}void upd(int x,int k){while(x<=Mxu)c[x]+=k,x+=x&-x;return;}
int ask(int x){int sum=0;while(x)sum+=c[x],x-=x&-x;return sum;}
void CDQsolve(int l,int r){
    if(l>=r)return;int mid=(l+r)>>1;
    CDQsolve(l,mid),CDQsolve(mid+1,r);
    int pl=l,pr=mid+1,pos=l-1;
    while(pr<=r){
        while(pl<=mid&&d[pl].x<=d[pr].x){
            if(!d[pl].val)upd(d[pl].y,1);
            tmp[++pos]=d[pl],pl++;
        }if(d[pr].val)
            Ans[d[pr].tim]+=d[pr].val*ask(d[pr].y);
        tmp[++pos]=d[pr],pr++;
    }for(int i=l;i<=pl-1;i++)
        if(!d[i].val)upd(d[i].y,-1);
    while(pl<=mid)tmp[++pos]=d[pl],pl++;
    for(int i=l;i<=r;i++)d[i]=tmp[i];return;
}
int main(){
    n=read(),Q=read();
    for(int i=1;i<=n;i++)
        a[i]=read(),d[++cnt]={i+a[i],i-a[i],0,0};
    for(int i=1;i<=Q;i++){
        string opt;cin>>opt;
        int x=read(),k=read();
        if(opt=="Modify")
            d[++cnt]={x+k,x-k,i,0},Ls[++cL]=x-k,a[x]=k;
        else{
            int p=x+a[x],q=x-a[x];
            ot.pb(i),Ls[++cL]=q+k,Ls[++cL]=q-k-1;
            d[++cnt]={p+k,q+k,i,1};
            d[++cnt]={p-k-1,q+k,i,-1};
            d[++cnt]={p+k,q-k-1,i,-1};
            d[++cnt]={p-k-1,q-k-1,i,1};
        }
    }sort(Ls+1,Ls+cL+1);
    cL=unique(Ls+1,Ls+cL+1)-Ls-1;
    for(int i=1;i<=cnt;i++)
        d[i].y=lower_bound(Ls+1,Ls+cL+1,d[i].y)-Ls,
        Mxu=max(Mxu,d[i].y);
    CDQsolve(1,cnt);for(int x:ot)cout<<Ans[x]<<"\n";
    return 0;
}
